SELECT 
FROM product p
LEFT JOIN category c ON p.category_id = c.id
LEFT JOIN sys_user u ON p.seller_id = u.id


        AND p.status = #{status}


        AND (p.title ILIKE CONCAT('%', #{keyword}, '%') OR p.description ILIKE CONCAT('%', #{keyword}, '%'))


        AND p.category_id = #{categoryId}


ORDER BY p.create_time DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM product p


        AND p.status = #{status}


        AND (p.title ILIKE CONCAT('%', #{keyword}, '%') OR p.description ILIKE CONCAT('%', #{keyword}, '%'))


        AND p.category_id = #{categoryId}

SELECT 
FROM product p
LEFT JOIN category c ON p.category_id = c.id
LEFT JOIN sys_user u ON p.seller_id = u.id
WHERE 1 = 1

    AND (
        p.title ILIKE CONCAT('%', #{keyword}, '%')
        OR p.description ILIKE CONCAT('%', #{keyword}, '%')
    )


    AND p.category_id = #{categoryId}


    AND p.status = #{status}

ORDER BY p.create_time DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM product p
WHERE 1 = 1

    AND (
        p.title ILIKE CONCAT('%', #{keyword}, '%')
        OR p.description ILIKE CONCAT('%', #{keyword}, '%')
    )


    AND p.category_id = #{categoryId}


    AND p.status = #{status}

SELECT p.id, p.title, p.description, p.price, p.category_id, p.seller_id, p.status, p.create_time, c.name AS category_name, seller.username AS seller_name, ( SELECT pi.image_url FROM product_image pi WHERE pi.product_id = p.id ORDER BY pi.id ASC LIMIT 1 ) AS main_image_url, '近期在售商品推荐' AS recommend_reason, 0 AS recommend_score FROM product p LEFT JOIN category c ON p.category_id = c.id LEFT JOIN sys_user seller ON p.seller_id = seller.id WHERE p.status = 'ON_SALE'
AND p.seller_id <> #{userId} AND NOT EXISTS ( SELECT 1 FROM order_info o2 WHERE o2.product_id = p.id AND o2.buyer_id = #{userId} AND o2.order_status IN ('WAIT_CONFIRM', 'TRADING', 'FINISHED') )
ORDER BY p.create_time DESC LIMIT #{size}
